467	/// C: `l_randomizePivot()` — produce a "random" `u32` to randomize pivot
468	/// selection when a partition is severely imbalanced.
469	///
470	/// C: uses `clock()` and `time()` as entropy sources via `memcpy` into a
471	/// `unsigned int` array whose elements are summed.
472	///
473	/// PORT NOTE: Rust uses `SystemTime` as an entropy source instead of
474	/// POSIX `clock()`/`time()`. The mixing is simplified (subsecond nanos XOR-
475	/// shifted) but serves the same purpose: breaking pathological patterns.
476	fn randomize_pivot() -> u32 {
477	    use std::time::{SystemTime, UNIX_EPOCH};
478	    let nanos = SystemTime::now()
479	        .duration_since(UNIX_EPOCH)
480	        .map(|d| d.subsec_nanos())
481	        .unwrap_or(0u32);
482	    nanos ^ nanos.wrapping_shr(16)
