501	/// C: `sort_comp(L, a, b)` — return `true` iff `stack[a] < stack[b]` per the
502	/// sort order: either the `<` operator (if arg 2 is nil) or the user's
503	/// comparison function at stack position 2.
504	///
505	/// ```c
506	/// static int sort_comp (lua_State *L, int a, int b) {
507	///   if (lua_isnil(L, 2))
508	///     return lua_compare(L, a, b, LUA_OPLT);
509	///   else {
510	///     int res;
511	///     lua_pushvalue(L, 2);
512	///     lua_pushvalue(L, a-1);
513	///     lua_pushvalue(L, b-2);
514	///     lua_call(L, 2, 1);
515	///     res = lua_toboolean(L, -1);
516	///     lua_pop(L, 1);
517	///     return res;
518	///   }
519	/// }
520	/// ```
521	///
522	/// The offsets `a-1` and `b-2` compensate for the function and first-argument
523	/// copies pushed before the respective values: `a-1` accounts for the function
524	/// push; `b-2` accounts for both the function push and the copy of `a`.
525	fn sort_comp(state: &mut LuaState, a: i32, b: i32) -> Result<bool, LuaError> {
526	    if state.type_at(2) == LuaType::Nil {
527	        // No user comparator: use the default `<` operator.
528	        return state.compare(a, b, CompareOp::Lt);
529	    }
530	    // User comparator at stack position 2.
531	    state.push_value_at(2);       // push function
532	    state.push_value_at(a - 1);   // push copy of a (compensate for function push)
533	    state.push_value_at(b - 2);   // push copy of b (compensate for function + a copy)
534	    // C: lua_call(L, 2, 1)
535	    state.call(2, 1)?;
536	    // C: res = lua_toboolean(L, -1); lua_pop(L, 1)
537	    // TODO(port): state.to_boolean(-1) → lua_toboolean (never fails); verify method name
538	    let res = state.to_boolean(-1);
539	    state.pop_n(1);
540	    Ok(res)
