543	/// C: `partition(L, lo, up)` — in-place partition around the pivot `P` that
544	/// is already on the top of the Lua stack.
545	///
546	/// Precondition: `a[lo] <= P == a[up-1] <= a[up]` and `P` is at stack top.
547	/// Postcondition: `a[lo..i-1] <= a[i] == P <= a[i+1..up]`; stack is clean.
548	/// Returns the final pivot index `i`.
549	///
550	/// ```c
551	/// static IdxT partition (lua_State *L, IdxT lo, IdxT up) {
552	///   IdxT i = lo;
553	///   IdxT j = up - 1;
554	///   for (;;) {
555	///     while ((void)lua_geti(L, 1, ++i), sort_comp(L, -1, -2)) {
556	///       if (l_unlikely(i == up - 1))
557	///         luaL_error(L, "invalid order function for sorting");
558	///       lua_pop(L, 1);
559	///     }
560	///     while ((void)lua_geti(L, 1, --j), sort_comp(L, -3, -1)) {
561	///       if (l_unlikely(j < i))
562	///         luaL_error(L, "invalid order function for sorting");
563	///       lua_pop(L, 1);
564	///     }
565	///     if (j < i) {
566	///       lua_pop(L, 1);
567	///       set2(L, up - 1, i);
568	///       return i;
569	///     }
570	///     set2(L, i, j);
571	///   }
572	/// }
573	/// ```
574	fn partition(state: &mut LuaState, lo: IdxT, up: IdxT) -> Result<IdxT, LuaError> {
575	    let mut i: IdxT = lo;
576	    let mut j: IdxT = up - 1;
577	    // Entry: stack top is P (pivot value).
578	    loop {
579	        // Advance i: find first a[i] >= P.
580	        // Stack during i-loop body: P(-2), a[i](-1)
581	        loop {
582	            i += 1;
583	            state.table_get_i(1, i as i64)?; // push a[i]
584	            if !sort_comp(state, -1, -2)? {
585	                // a[i] >= P: leave a[i] on stack and exit
586	                break;
587	            }
588	            // a[i] < P; check for invalid comparator
589	            if i == up - 1 {
590	                return Err(LuaError::runtime(format_args!(
591	                    "invalid order function for sorting"
592	                )));
593	            }
594	            state.pop_n(1); // remove a[i]
595	        }
596	        // Retreat j: find last a[j] <= P.
597	        // Stack during j-loop body: P(-3), a[i](-2), a[j](-1)
598	        loop {
599	            // PERF(port): wrapping_sub mirrors C unsigned IdxT behaviour for edge cases
600	            j = j.wrapping_sub(1);
