602	            if !sort_comp(state, -3, -1)? {
603	                // P >= a[j]: leave a[j] on stack and exit
604	                break;
605	            }
606	            // P < a[j]; check for invalid comparator
607	            if j < i {
608	                return Err(LuaError::runtime(format_args!(
609	                    "invalid order function for sorting"
610	                )));
611	            }
612	            state.pop_n(1); // remove a[j]
613	        }
614	        // Stack: P(-3), a[i](-2), a[j](-1)
615	        if j < i {
616	            // No out-of-place elements; finalize: place pivot at position i.
617	            state.pop_n(1); // pop a[j]; stack: P(-2), a[i](-1)
618	            set2(state, up - 1, i)?; // table[up-1] = a[i], table[i] = P; stack clean
619	            return Ok(i);
